class SecureLogFormatter(logging.Formatter):
    """Custom formatter that sanitizes log messages to prevent log injection."""

    def format(self, record):
        # Sanitize the message to prevent log injection attacks
        if isinstance(record.msg, str):
            # Remove or escape newlines and carriage returns to prevent log forging
            record.msg = record.msg.replace('\r\n', '\\r\\n')
            record.msg = record.msg.replace('\r', '\\r')
            record.msg = record.msg.replace('\n', '\\n')
            # Remove ANSI escape sequences
            record.msg = re.sub(r'\x1b\[[0-9;]*m', '', record.msg)

        return super().format(record)


