class RotatingFileHandlerSecure(logging.handlers.RotatingFileHandler):
    """Rotating file handler that sets secure permissions on rotated files."""

    def __init__(self, *args, secure_permissions=None, **kwargs):
        self.secure_permissions = secure_permissions or (stat.S_IRUSR | stat.S_IWUSR)
        super().__init__(*args, **kwargs)
        self._set_permissions(self.baseFilename)

    def _set_permissions(self, filepath):
        """Set secure permissions on a file."""
        if sys.platform != 'win32' and os.path.exists(filepath):
            os.chmod(filepath, self.secure_permissions)

    def doRollover(self):
        """Override to set secure permissions on rotated files."""
        super().doRollover()
        # Set permissions on the new log file
        self._set_permissions(self.baseFilename)
        # Set permissions on rotated files
        for i in range(1, self.backupCount + 1):
            rotated_file = f"{self.baseFilename}.{i}"
            self._set_permissions(rotated_file)


