class SensitiveDataFilter(logging.Filter):
    """Filter that redacts sensitive data from log messages."""

    SENSITIVE_PATTERNS = [
        (re.compile(r'password\s*[=:]\s*\S+', re.IGNORECASE), 'password=***REDACTED***'),
        (re.compile(r'token\s*[=:]\s*\S+', re.IGNORECASE), 'token=***REDACTED***'),
        (re.compile(r'api[_-]?key\s*[=:]\s*\S+', re.IGNORECASE), 'api_key=***REDACTED***'),
        (re.compile(r'secret\s*[=:]\s*\S+', re.IGNORECASE), 'secret=***REDACTED***'),
        (re.compile(r'\b\d{3}-\d{2}-\d{4}\b'), '***SSN-REDACTED***'),  # SSN pattern
        (re.compile(r'\b\d{4}[\s-]?\d{4}[\s-]?\d{4}[\s-]?\d{4}\b'), '***CC-REDACTED***'),  # Credit card
    ]

    def filter(self, record):
        if isinstance(record.msg, str):
            for pattern, replacement in self.SENSITIVE_PATTERNS:
                record.msg = pattern.sub(replacement, record.msg)
        if record.args:
            new_args = []
            for arg in (record.args if isinstance(record.args, tuple) else (record.args,)):
                if isinstance(arg, str):
                    for pattern, replacement in self.SENSITIVE_PATTERNS:
                        arg = pattern.sub(replacement, arg)
                new_args.append(arg)
            record.args = tuple(new_args) if isinstance(record.args, tuple) else new_args[0]
        return True


def setup_application_logger(
    name="secure_app",
    log_dir=None,
    log_level=logging.INFO,
    max_bytes=10 * 1024 * 1024,
    backup_count=5,
    use_timed_rotation=False,
    rotation_when='midnight',
    rotation_interval=1,
    timed_backup_count=30,
    enable_console=True,
    enable_sensitive_filter=True
):
    """
    Set up a secure application logger with rotation and proper permissions.

    Args:
        name: Logger name.
        log_dir: Directory for log files.
        log_level: Logging level.
        max_bytes: Max bytes per log file (for size-based rotation).
        backup_count: Number of backup files (for size-based rotation).
        use_timed_rotation: Use time-based rotation instead of size-based.
        rotation_when: When to rotate (for time-based rotation).
        rotation_interval: Rotation interval (for time-based rotation).
        timed_backup_count: Number of backups (for time-based rotation).
        enable_console: Also log to console.
        enable_sensitive_filter: Enable sensitive data filtering.

    Returns:
        Configured logger instance.
    """
    logger = logging.getLogger(name)
    logger.setLevel(log_level)

    # Clear existing handlers
    logger.handlers.clear()

    # Set up secure log handler
    secure_handler = SecureLogHandler(
        log_dir=log_dir,
        log_filename=f"{name}.log"
    )

    # Create file handler with rotation
    if use_timed_rotation:
        file_handler = secure_handler.create_timed_rotating_handler(
            when=rotation_when,
            interval=rotation_interval,
            backup_count=timed_backup_count
        )
    else:
        file_handler = secure_handler.create_rotating_file_handler(
            max_bytes=max_bytes,
            backup_count=backup_count
        )

    file_handler.setLevel(log_level)
    logger.addHandler(file_handler)

    # Add sensitive data filter
    if enable_sensitive_filter:
        sensitive_filter = SensitiveDataFilter()
        logger.addFilter(sensitive_filter)

    # Console handler (optional)
    if enable_console:
        console_handler = logging.StreamHandler(sys.stdout)
        console_handler.setLevel(log_level)
        console_formatter = SecureLogFormatter(
            fmt='%(asctime)s - %(name)s - %(levelname)s - %(message)s',
            datefmt='%Y-%m-%d %H:%M:%S'
        )
        console_handler.setFormatter(console_formatter)
        if enable_sensitive_filter:
            console_handler.addFilter(SensitiveDataFilter())
        logger.addHandler(console_handler)

    # Prevent log propagation to root logger
    logger.propagate = False

    return logger


def verify_log_security(log_dir):
    """
    Verify the security of log files in a directory.

    Args:
        log_dir: Path to the log directory.

    Returns:
        dict with security check results.
    """
    results = {
        'directory_exists': False,
        'directory_permissions_secure': False,
        'directory_owner_correct': False,
        'files_checked': 0,
        'insecure_files': [],
        'symlink_files': [],
        'overall_secure': False
    }

    log_path = Path(log_dir).resolve()

    if not log_path.exists():
        return results

    results['directory_exists'] = True

    if sys.platform != 'win32':
        # Check directory permissions
        dir_stat = os.stat(str(log_path))
        dir_mode = stat.S_IMODE(dir_stat.st_mode)

        insecure_bits = (
            stat.S_IRGRP | stat.S_IWGRP | stat.S_IXGRP |
            stat.S_IROTH | stat.S_IWOTH | stat.S_IXOTH
        )

        results['directory_permissions_secure'] = not (dir_mode & insecure_bits)
        results['directory_owner_correct'] = dir_stat.st_uid == os.getuid()

        # Check each file
        for filepath in log_path.iterdir():
            if filepath.is_file():
                results['files_checked'] += 1

                if filepath.is_symlink():
                    results['symlink_files'].append(str(filepath))

                file_stat = os.stat(str(filepath))
                file_mode = stat.S_IMODE(file_stat.st_mode)

                if file_mode & insecure_bits:
                    results['insecure_files'].append({
                        'file': str(filepath),
                        'permissions': oct(file_mode)
                    })
    else:
        results['directory_permissions_secure'] = True
        results['directory_owner_correct'] = True

    results['overall_secure'] = (
        results['directory_exists'] and
        results['directory_permissions_secure'] and
        results['directory_owner_correct'] and
        len(results['insecure_files']) == 0 and
        len(results['symlink_files']) == 0
    )

    return results


